module parallel2serial(
  input clk,
  input rst_n,
  input [3:0] d,
  output dout,
  output valid_out
);

  reg [1:0] cnt;
  reg [3:0] data;
  reg valid;

  always @(posedge clk) begin
    if (!rst_n) begin
      cnt <= 2'b00;
    end else begin
      cnt <= cnt + 1'b1;
    end
  end

  always @(posedge clk) begin
    if (!rst_n) begin
      data <= 4'b0000;
      valid <= 1'b0;
    end else begin
      if (cnt == 2'b11) begin
        data <= d;
        valid <= 1'b1;
      end else begin
        data <= {data[2:0], data[3]};
        valid <= 1'b0;
      end
    end
  end

  assign dout = data[3];
  assign valid_out = valid;

endmodule
